const supabase = { from:(t)=>({ select:async()=>{ if(DEMO_MODE) return {data:null,error:null}; try{ const r=await fetch(`${SUPABASE_URL}/rest/v1/${t}?select=*`,{headers:{apikey:SUPABASE_ANON_KEY,Authorization:`Bearer ${SUPABASE_ANON_KEY}`}}); return {data:await r.json(),error:null}; }catch(e){return {data:null,error:e};} }, insert:async(row)=>{ if(DEMO_MODE) return {data:row,error:null}; try{ const r=await fetch(`${SUPABASE_URL}/rest/v1/${t}`,{method:"POST",headers:{apikey:SUPABASE_ANON_KEY,Authorization:`Bearer ${SUPABASE_ANON_KEY}`,"Content-Type":"application/json",Prefer:"return=representation"},body:JSON.stringify(row)}); return {data:await r.json(),error:null}; }catch(e){return {data:null,error:e};} } }), storage:{ upload:async(b,p,f)=>{ if(DEMO_MODE) return {data:{path:p},error:null}; try{ await fetch(`${SUPABASE_URL}/storage/v1/object/${b}/${p}`,{method:"POST",headers:{apikey:SUPABASE_ANON_KEY,Authorization:`Bearer ${SUPABASE_ANON_KEY}`},body:f}); return {data:{path:p},error:null}; }catch(e){return {data:null,error:e};} }, getPublicUrl:(b,p)=>DEMO_MODE?`https://images.unsplash.com/photo-1441984904996-e0b6ba687e04?w=600&h=400&fit=crop`:`${SUPABASE_URL}/storage/v1/object/public/${b}/${p}` } };
const stripe = { createCheckout:async()=>{ if(DEMO_MODE) return new Promise(r=>setTimeout(()=>r({success:true}),2000)); } };

