// ═══════════════════════════════════════════
// UTILS
// ═══════════════════════════════════════════
const haversine = (lat1,lng1,lat2,lng2) => { const R=6371,dLat=(lat2-lat1)*Math.PI/180,dLng=(lng2-lng1)*Math.PI/180,a=Math.sin(dLat/2)**2+Math.cos(lat1*Math.PI/180)*Math.cos(lat2*Math.PI/180)*Math.sin(dLng/2)**2; return R*2*Math.atan2(Math.sqrt(a),Math.sqrt(1-a)); };
const Stars = ({r,n}) => <div style={{display:"flex",alignItems:"center",gap:3}}>{[1,2,3,4,5].map(i=><StarIcon key={i} filled={i<=Math.round(r)}/>)}<span style={{fontSize:12,color:C.muted,marginLeft:4}}>{r} ({n})</span></div>;

