function Carousel({photos,h=220}){const[i,setI]=useState(0);if(!photos?.length)return<div style={{width:"100%",height:h,background:C.lightGray,display:"flex",alignItems:"center",justifyContent:"center",color:C.muted}}><CameraIcon/></div>;return(<div style={{position:"relative",width:"100%",height:h,overflow:"hidden"}}><img src={photos[i]} alt="" style={{width:"100%",height:"100%",objectFit:"cover"}}/>{photos.length>1&&<><button onClick={e=>{e.stopPropagation();setI((i-1+photos.length)%photos.length)}} style={{position:"absolute",left:8,top:"50%",transform:"translateY(-50%)",background:"rgba(0,0,0,0.4)",border:"none",borderRadius:"50%",width:30,height:30,display:"flex",alignItems:"center",justifyContent:"center",cursor:"pointer",color:"#fff"}}><ChevL/></button><button onClick={e=>{e.stopPropagation();setI((i+1)%photos.length)}} style={{position:"absolute",right:8,top:"50%",transform:"translateY(-50%)",background:"rgba(0,0,0,0.4)",border:"none",borderRadius:"50%",width:30,height:30,display:"flex",alignItems:"center",justifyContent:"center",cursor:"pointer",color:"#fff"}}><ChevR/></button><div style={{position:"absolute",bottom:8,left:"50%",transform:"translateX(-50%)",display:"flex",gap:4}}>{photos.map((_,j)=><div key={j} style={{width:6,height:6,borderRadius:"50%",background:j===i?"#fff":"rgba(255,255,255,0.5)"}}/>)}</div></>}</div>);}

// ═══════════════════════════════════════════
// QR CODE (simple SVG generator)
// ═══════════════════════════════════════════
function QRCodeSimple({text,size=120}){
  // Simple visual placeholder — in prod use a real QR lib
  const cells=[];const s=21;for(let y=0;y<s;y++)for(let x=0;x<s;x++){const isCorner=(x<7&&y<7)||(x>=s-7&&y<7)||(x<7&&y>=s-7);const hash=((text.charCodeAt((x+y*3)%text.length)||0)*31+x*7+y*13)%100;if(isCorner||hash<40)cells.push(<rect key={`${x}-${y}`} x={x*(size/s)} y={y*(size/s)} width={size/s+0.5} height={size/s+0.5} fill={C.dark}/>);}
  return <svg width={size} height={size} viewBox={`0 0 ${size} ${size}`} style={{borderRadius:8}}><rect width={size} height={size} fill="white"/>{cells}</svg>;
}

